1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT = 15;
12	const FIXED_FEE = 5;
13	const ALIKE_COMPONENT_BLOCK_SIZE = 3;
14	const ALIKE_COMPONENT_BLOCK_PRICE = 60;
15	
16	function applyFirstInsuranceSurcharge(amount: number): number {
17	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
18	}
19	
20	function applySubsequentContractDiscount(amount: number): number {
21	  return Math.ceil((amount * (100 - SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT)) / 100);
22	}
23	
24	function countByType(items: { type: string }[]): Record<string, number> {
25	  return items.reduce<Record<string, number>>((counts, item) => {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	    return counts;
28	  }, {});
29	}
30	
31	function priceForType(type: string, count: number): number {
32	  const blocks = Math.floor(count / ALIKE_COMPONENT_BLOCK_SIZE);
33	  const leftover = count % ALIKE_COMPONENT_BLOCK_SIZE;
34	  return blocks * ALIKE_COMPONENT_BLOCK_PRICE + leftover * BASE_PRICES[type];
35	}
36	
37	function quoteBasePrice(items: { type: string }[]): number {
38	  const counts = countByType(items);
39	  return Object.entries(counts).reduce(
40	    (total, [type, count]) => total + priceForType(type, count),
41	    0
42	  );
43	}
44	
45	function applyRatioIf(
46	  condition: boolean,
47	  basePrice: number,
48	  numerator: number,
49	  denominator: number
50	): number {
51	  return condition ? (basePrice * numerator) / denominator : basePrice;
52	}
53	
54	function applyCursedSurcharge(items: { cursed: boolean }[], basePrice: number): number {
55	  const hasCursed = items.some((item) => item.cursed);
56	  return applyRatioIf(hasCursed, basePrice, 3, 2);
57	}
58	
59	function applyEnchantedSurcharge(items: { enchantment: number }[], basePrice: number): number {
60	  const hasHighEnchant = items.some((item) => item.enchantment >= 5);
61	  return applyRatioIf(hasHighEnchant, basePrice, 13, 10);
62	}
63	
64	function applyLoyaltyDiscount(yearsWithMHPCO: number, basePrice: number): number {
65	  return applyRatioIf(yearsWithMHPCO >= 2, basePrice, 8, 10);
66	}
67	
68	export function runScenario(scenario: any): unknown {
69	  const results: { premium: number }[] = [];
70	  let quoteCount = 0;
71	  for (const step of scenario.steps) {
72	    const items = step.items;
73	    const basePrice = quoteBasePrice(items);
74	    const withCursed = applyCursedSurcharge(items, basePrice);
75	    const withEnchanted = applyEnchantedSurcharge(items, withCursed);
76	    const withLoyalty = applyLoyaltyDiscount(scenario.customer.yearsWithMHPCO, withEnchanted);
77	    const withContractAdjustment =
78	      quoteCount === 0
79	        ? applyFirstInsuranceSurcharge(withLoyalty)
80	        : applySubsequentContractDiscount(withLoyalty);
81	    const premium = withContractAdjustment + FIXED_FEE;
82	    results.push({ premium });
83	    quoteCount++;
84	  }
85	  return { results };
86	}
